targets.expr:
sum(
  kube_pod_container_resource_requests{
    namespace="default",
    container="flink-main-container",
    resource="memory",
    pod=~"flink-taskmanager-.*"
  }
) / 1024 / 1024

100 *
sum(rate(flink_taskmanager_job_task_operator_rocksdb_block_cache_hit{
  task_name=~"$task_name",
  subtask_index=~"$subtask_index",
  job_id=~"$job_id"
}[20s]))
/
(
sum(rate(flink_taskmanager_job_task_operator_rocksdb_block_cache_hit{
  task_name=~"$task_name",
  subtask_index=~"$subtask_index",
  job_id=~"$job_id"
}[20s]))
+
sum(rate(flink_taskmanager_job_task_operator_rocksdb_block_cache_miss{
  task_name=~"$task_name",
  subtask_index=~"$subtask_index",
  job_id=~"$job_id"
}[20s]))
)
